INSERT INTO `faqs` (`id`, `question`, `answer`, `category`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(2, 'What exactly does PadosiAgent do for me?', 'PadosiAgent helps you find your Trusted, IRDAI licensed insurance PadosiAgent in your neighbourhood. Whether you want to Buy a new policy, need help with your claim, or want your existing policies reviewed we connect you with your verified local PadosiAgent who specializes in your needs.', 'general', 1, 1, '2026-03-30 16:20:36', '2026-03-30 16:20:36'),
(3, 'Is PadosiAgent really free for me?', 'Yes, 100% free for you! You don\'t have to pay anything for finding your PadosiAgent.', 'general', 2, 1, '2026-03-30 16:21:11', '2026-03-30 16:21:11'),
(4, 'Will I get spam calls after using PadosiAgent?', 'Absolutely not! Only YOU can 1st initiate contact via call or WhatsApp. Post that Only that PadosiAgent will be in your touch for your requirements. This means zero spam calls for you.', 'general', 3, 1, '2026-03-30 16:21:46', '2026-03-30 16:21:46'),
(5, 'How do I know if my PadosiAgent is trustworthy?', 'Every PadosiAgent is IRDAI (Insurance Regulatory and Development Authority of India) licensed and background verified. You can also see their customer ratings, reviews, years of experience, and specializations before you connect.', 'general', 4, 1, '2026-03-30 16:22:41', '2026-03-30 16:22:41'),
(6, 'How quickly can I get help with my insurance claim?', 'Your Claims Expert responds once you initiate to Call or WhatsApp. They\'ll guide you through every step from filing your paperwork to following up with the insurance company until your genuine claim get resolved. (Please note that Claims Expert PadosiAgent may charge consultation mentioned in their profile page for this Service)', 'general', 5, 1, '2026-03-30 16:23:15', '2026-03-30 16:23:15'),
(7, 'What documents do I need for my policy review?', 'Just bring your existing policy documents (Health, Life, Motor, or any other insurance). Your PadosiAgent will review your coverage, identify gaps, check if you\'re overpaying, and suggest optimizations. (Please note that Insurance Expert PadosiAgent may charge consultation mentioned in their profile page for this Service)', 'general', 6, 1, '2026-03-30 16:23:54', '2026-03-30 16:23:54'),
(8, 'Can I find a PadosiAgent who speaks my language?', 'Yes! Each PadosiAgent profile shows the languages they speak. You can easily find your PadosiAgent who communicates in Hindi, English, Marathi, Tamil, Telugu, or other regional languages.', 'general', 7, 1, '2026-03-30 16:25:12', '2026-03-30 16:25:12'),
(9, 'What if I don\'t like the PadosiAgent I connected with?', 'No problem! You can simply find and connect with another PadosiAgent. You can also leave a review about your experience to help other users make informed choices.', 'general', 8, 1, '2026-03-30 16:26:15', '2026-03-30 16:26:15');
